-- ============================================================
--  Amazon India Store – MySQL Import
--  Generated : 2026-04-06
--  Sellers   : 75     Customers : 320    Products : 180
--  Orders    : 2100   Reviews   : 1850   Returns  : 420
--  Transactions : 2100  (one per order, same order_id)
-- 
--  FK Relationships
--  ───────────────────────────────────────────────────────────
--  products.seller_id     → sellers.seller_id
--  orders.customer_id     → customers.customer_id
--  orders.product_id      → products.product_id
--  orders.seller_id       → sellers.seller_id        ★ new
--  reviews.product_id     → products.product_id
--  reviews.customer_id    → customers.customer_id
--  reviews.order_id       → orders.order_id
--  returns.order_id       → orders.order_id
--  returns.customer_id    → customers.customer_id
--  returns.product_id     → products.product_id
--  transactions.order_id  → orders.order_id          ★ 1-to-1
--  transactions.customer_id→ customers.customer_id
--  transactions.seller_id → sellers.seller_id        ★ new
-- ============================================================

CREATE DATABASE IF NOT EXISTS amazon_india_store;
USE amazon_india_store;

SET FOREIGN_KEY_CHECKS = 0;

-- ------------------------------------------------------------
-- Table: sellers  (75 rows)
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `sellers`;
CREATE TABLE `sellers` (
  `seller_id`        VARCHAR(10)  NOT NULL,
  `seller_name`      VARCHAR(100),
  `gstin`            VARCHAR(16),
  `primary_category` VARCHAR(60),
  `city`             VARCHAR(60),
  `state`            VARCHAR(60),
  `fulfillment_type` VARCHAR(12),
  `seller_rating`    DECIMAL(3,1),
  `total_sales_inr`  BIGINT,
  `total_listings`   INT,
  `feedback_count`   INT,
  `joined_date`      VARCHAR(12),
  `account_health`   VARCHAR(12),
  `return_rate_pct`  DECIMAL(5,2),
  `defect_rate_pct`  DECIMAL(5,2),
  `on_time_ship_pct` DECIMAL(5,2),
  `avg_response_hrs` DECIMAL(5,2),
  `brand_registered` VARCHAR(5),
  PRIMARY KEY (`seller_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- Table: customers  (320 rows)
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `customers`;
CREATE TABLE `customers` (
  `customer_id`        VARCHAR(12)   NOT NULL,
  `full_name`          VARCHAR(100),
  `gender`             VARCHAR(2),
  `email`              VARCHAR(120),
  `mobile`             VARCHAR(18),
  `city`               VARCHAR(60),
  `state`              VARCHAR(60),
  `pincode`            INT,
  `prime_member`       VARCHAR(10),
  `account_created`    VARCHAR(12),
  `total_orders`       INT,
  `lifetime_spend_inr` DECIMAL(12,2),
  `preferred_category` VARCHAR(60),
  `kyc_verified`       VARCHAR(5),
  `gst_registered`     VARCHAR(5),
  PRIMARY KEY (`customer_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- Table: products  (180 rows)
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `products`;
CREATE TABLE `products` (
  `product_id`         VARCHAR(12)   NOT NULL,
  `asin`               VARCHAR(12),
  `product_name`       VARCHAR(250),
  `category`           VARCHAR(60),
  `brand`              VARCHAR(80),
  `seller_id`          VARCHAR(10),
  `mrp_inr`            INT,
  `selling_price`      DECIMAL(10,2),
  `cost_price`         INT,
  `gst_percent`        INT,
  `rating`             DECIMAL(3,1),
  `review_count`       INT,
  `stock_qty`          INT,
  `weight_kg`          DECIMAL(6,2),
  `is_prime`           VARCHAR(5),
  `fulfilled_by`       VARCHAR(10),
  `launch_date`        VARCHAR(12),
  `discount_pct`       INT,
  `return_window_days` INT,
  PRIMARY KEY (`product_id`),
  FOREIGN KEY (`seller_id`) REFERENCES `sellers`(`seller_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- Table: orders  (2100 rows)
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `orders`;
CREATE TABLE `orders` (
  `order_id`          VARCHAR(22)   NOT NULL,
  `customer_id`       VARCHAR(12),
  `product_id`        VARCHAR(12),
  `seller_id`         VARCHAR(10),
  `order_date`        VARCHAR(12),
  `ship_date`         VARCHAR(12),
  `delivery_date`     VARCHAR(12),
  `quantity`          INT,
  `unit_price_inr`    DECIMAL(10,2),
  `subtotal_inr`      DECIMAL(12,2),
  `shipping_fee_inr`  DECIMAL(8,2),
  `gst_inr`           DECIMAL(10,2),
  `discount_inr`      INT,
  `order_total_inr`   DECIMAL(12,2),
  `payment_method`    VARCHAR(25),
  `shipping_type`     VARCHAR(30),
  `order_status`      VARCHAR(20),
  `warehouse_state`   VARCHAR(60),
  `invoice_no`        VARCHAR(12),
  `is_business_order` VARCHAR(5),
  `promo_applied`     VARCHAR(15),
  PRIMARY KEY (`order_id`),
  FOREIGN KEY (`customer_id`) REFERENCES `customers`(`customer_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  FOREIGN KEY (`product_id`)  REFERENCES `products`(`product_id`)   ON DELETE SET NULL ON UPDATE CASCADE,
  FOREIGN KEY (`seller_id`)   REFERENCES `sellers`(`seller_id`)     ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- Table: reviews  (1850 rows)
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `reviews`;
CREATE TABLE `reviews` (
  `review_id`         VARCHAR(14)  NOT NULL,
  `product_id`        VARCHAR(12),
  `customer_id`       VARCHAR(12),
  `order_id`          VARCHAR(22),
  `review_date`       VARCHAR(12),
  `rating`            TINYINT,
  `review_title`      VARCHAR(120),
  `review_language`   VARCHAR(12),
  `verified_purchase` VARCHAR(5),
  `helpful_votes`     INT,
  `total_votes`       INT,
  `vine_review`       VARCHAR(5),
  `image_attached`    VARCHAR(5),
  `seller_response`   VARCHAR(5),
  PRIMARY KEY (`review_id`),
  FOREIGN KEY (`product_id`)  REFERENCES `products`(`product_id`)   ON DELETE SET NULL ON UPDATE CASCADE,
  FOREIGN KEY (`customer_id`) REFERENCES `customers`(`customer_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  FOREIGN KEY (`order_id`)    REFERENCES `orders`(`order_id`)       ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- Table: returns  (420 rows)
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `returns`;
CREATE TABLE `returns` (
  `return_id`           VARCHAR(12)  NOT NULL,
  `order_id`            VARCHAR(22),
  `customer_id`         VARCHAR(12),
  `product_id`          VARCHAR(12),
  `return_request_date` VARCHAR(12),
  `return_reason`       VARCHAR(40),
  `return_status`       VARCHAR(20),
  `refund_amount_inr`   DECIMAL(12,2),
  `refund_method`       VARCHAR(35),
  `days_to_return`      INT,
  `condition_received`  VARCHAR(12),
  `pickup_agent`        VARCHAR(20),
  `replacement_issued`  VARCHAR(5),
  PRIMARY KEY (`return_id`),
  FOREIGN KEY (`order_id`)    REFERENCES `orders`(`order_id`)       ON DELETE SET NULL ON UPDATE CASCADE,
  FOREIGN KEY (`customer_id`) REFERENCES `customers`(`customer_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  FOREIGN KEY (`product_id`)  REFERENCES `products`(`product_id`)   ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- Table: transactions  (2100 rows — 1-to-1 with orders)
-- ------------------------------------------------------------
DROP TABLE IF EXISTS `transactions`;
CREATE TABLE `transactions` (
  `transaction_id`     VARCHAR(14)  NOT NULL,
  `order_id`           VARCHAR(22),
  `customer_id`        VARCHAR(12),
  `seller_id`          VARCHAR(10),
  `transaction_date`   VARCHAR(12),
  `amount_inr`         DECIMAL(12,2),
  `payment_method`     VARCHAR(25),
  `transaction_status` VARCHAR(10),
  `gateway_reference`  VARCHAR(15),
  `bank_name`          VARCHAR(35),
  `upi_id`             VARCHAR(50),
  `currency`           CHAR(3),
  `failure_reason`     VARCHAR(60),
  `is_refund`          VARCHAR(5),
  `linked_return_id`   VARCHAR(12),
  PRIMARY KEY (`transaction_id`),
  FOREIGN KEY (`order_id`)    REFERENCES `orders`(`order_id`)       ON DELETE SET NULL ON UPDATE CASCADE,
  FOREIGN KEY (`customer_id`) REFERENCES `customers`(`customer_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  FOREIGN KEY (`seller_id`)   REFERENCES `sellers`(`seller_id`)     ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


SET FOREIGN_KEY_CHECKS = 1;

-- ============================================================
-- END OF SCRIPT
-- ============================================================